import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"zkqes civic-terminal rebrand — design spec","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-05-04-zkqes-civic-terminal-rebrand-design.md","filePath":"superpowers/specs/2026-05-04-zkqes-civic-terminal-rebrand-design.md","lastUpdated":1777921494000}'),i={name:"superpowers/specs/2026-05-04-zkqes-civic-terminal-rebrand-design.md"};function n(d,e,r,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="zkqes-civic-terminal-rebrand-—-design-spec" tabindex="-1">zkqes civic-terminal rebrand — design spec <a class="header-anchor" href="#zkqes-civic-terminal-rebrand-—-design-spec" aria-label="Permalink to &quot;zkqes civic-terminal rebrand — design spec&quot;">​</a></h1><p><strong>Date:</strong> 2026-05-04 <strong>Status:</strong> locked, awaiting <code>chore/civic-terminal-spec</code> merge to main; orchestration plan + per-worker plan + BRAND.md amendment commit dispatch follow merge <strong>Wireframe bundle reference:</strong> <code>/tmp/zkqes-design/zk-qes-3/</code> (Claude Design handoff, decompressed; the 326-line <code>civic-terminal.css</code> token layer + 15 wireframe artboards across 5 surfaces) <strong>Founder direction reference:</strong> 2026-05-04 thread — variant D selected; full rebrand · replace · amend <strong>Prior visual baseline:</strong> civic-monumental (<code>#60</code> LandingHero, <code>--bone</code> / <code>--ink</code> / <code>--sovereign</code> / <code>--seal</code>, EB Garamond + Inter Tight) <strong>Prior prototype (superseded by lead, retained as reference):</strong> <code>feat/v5_3-zkqes-d-prototype @ c242778</code> — gated <code>?variant=civic-terminal</code> opt-in route, will not ship <strong>Orchestration plan:</strong> TBD — <code>2026-05-04-zkqes-civic-terminal-orchestration.md</code> (lands after this spec locks) <strong>Per-worker plan (web):</strong> TBD — <code>2026-05-04-zkqes-civic-terminal-web.md</code> (lands after orchestration plan) <strong>BRAND.md amendment commit:</strong> TBD — <code>chore/brand-civic-terminal</code> from main, founder-reviewed in isolation; <strong>gate</strong> for landing/docs implementation branches</p><h2 id="_0-goal-one-sentence" tabindex="-1">0. Goal (one sentence) <a class="header-anchor" href="#_0-goal-one-sentence" aria-label="Permalink to &quot;0. Goal (one sentence)&quot;">​</a></h2><p>Replace the civic-monumental visual identity (EB Garamond + bone/ink/sovereign/seal palette, currently shipped at <code>zkqes.org</code> via <code>LandingHero</code>) with the civic-terminal direction (Curve.fi-era panel chrome × UA + EU civic-document × pure monospace VT323/IBM Plex Mono) across all three subdomains, sequenced BRAND.md → landing → docs → app.</p><h2 id="_1-locked-decisions-founder-confirmed-2026-05-04" tabindex="-1">1. Locked decisions (founder confirmed 2026-05-04) <a class="header-anchor" href="#_1-locked-decisions-founder-confirmed-2026-05-04" aria-label="Permalink to &quot;1. Locked decisions (founder confirmed 2026-05-04)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Q</th><th>Decision</th><th>Implication</th></tr></thead><tbody><tr><td><strong>Q1</strong></td><td><strong>Variant D (&quot;Curve router · dense&quot;)</strong> as the home shape</td><td>Marquee status bar + 3-column 260/1fr/260 (prereqs / binding statement / attestation chain). Heavy chrome, terminal-density data layout.</td></tr><tr><td><strong>Q2</strong></td><td><strong>Full rebrand</strong> across landing + docs.zkqes.org + (post-§9.4) app.zkqes.org</td><td>All three subdomains carry the same token layer + grammar. Brand fragmentation across surfaces is rejected.</td></tr><tr><td><strong>Q3</strong></td><td><strong>Replace <code>LandingHero</code></strong> outright (no A/B layer)</td><td>The <code>?variant=civic-terminal</code> flag prototype shipped at <code>c242778</code> is <strong>superseded</strong> per lead 2026-05-04. Implementation branches replace <code>LandingHero</code> directly. The prototype branch may be deleted at lead&#39;s discretion or kept as a frozen reference.</td></tr><tr><td><strong>Q4</strong></td><td><strong>Amend BRAND.md</strong> before any implementation</td><td>Token table + component grammar lock in <code>BRAND.md</code> before code consumes them. Three sections added (Visual Language, Type Stack, Component Grammar); no existing sections rewritten. Founder reviews the amendment in isolation.</td></tr></tbody></table><h2 id="_2-surface-inventory" tabindex="-1">2. Surface inventory <a class="header-anchor" href="#_2-surface-inventory" aria-label="Permalink to &quot;2. Surface inventory&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>Domain</th><th>Build target</th><th>Hosting</th><th>Scope this rebrand</th><th>Implementation cost</th></tr></thead><tbody><tr><td>Landing</td><td><code>zkqes.org</code></td><td><code>VITE_TARGET=landing</code></td><td>GH Pages, <code>pages.yml</code></td><td>Replace <code>LandingHero</code> with <code>CivicTerminalLanding</code>; preserve all current routes (<code>/ceremony</code>, <code>/ceremony/contribute</code>, etc.); pre-launch empty-states for the marquee + ledger + tabs (see §3)</td><td>~3-4 days web-eng</td></tr><tr><td>Docs</td><td><code>docs.zkqes.org</code></td><td>VitePress</td><td>GH Pages branch (<code>gh-pages-docs</code>, <code>pages-docs.yml</code>)</td><td>Rewrite <code>docs/.vitepress/theme/custom.css</code> to rebind <code>--vp-c-*</code> tokens against civic-terminal palette; webfont swap (EB Garamond → VT323 + IBM Plex Mono); nav/sidebar treatment to mirror landing&#39;s <code>.ct-tab</code> grammar</td><td>~2 days web-eng</td></tr><tr><td>App</td><td><code>app.zkqes.org</code></td><td><code>VITE_TARGET=app</code></td><td>TBD post-§9.4 (Cloudflare Pages or Vercel candidates)</td><td>Full register / rotate / verify / account / escrow flow port onto <code>.ct-panel</code> / <code>.ct-field</code> / <code>.ct-tab</code> / <code>.ct-btn--primary</code> grammar; ~30 React components touched</td><td>~3-5 days web-eng (deferred; <strong>gated on Sepolia §9.4 / <code>#18</code></strong>)</td></tr></tbody></table><p><strong>Out of scope (regardless of subdomain):</strong></p><ul><li>VS Code / IntelliJ extension UI (no extension exists)</li><li>README / changelog visual treatment (markdown rendering, GitHub-side; out of brand control)</li><li>Email templates (no email surface in current product)</li><li>Marketing collateral PDFs / X-thread / HN-launch graphics (handled by marketer; spec calls out the token reference path so marketer can pull tokens for any visual deliverables)</li><li>Any backend service UI (no admin dashboards exist; ceremony coordinator is markdown + status JSON)</li></ul><h2 id="_3-pre-launch-adaptation" tabindex="-1">3. Pre-launch adaptation <a class="header-anchor" href="#_3-pre-launch-adaptation" aria-label="Permalink to &quot;3. Pre-launch adaptation&quot;">​</a></h2><p>The wireframe bundle was designed as POST-launch UI: marquee shows &quot;round 2/3 · provers online: 12 · ● live&quot;, right column shows recent <strong>bindings</strong> (i.e., users who have already registered onchain), middle-column tabs (Register / Rotate / Verify) are active. We are pre-launch: no ceremony rounds run, no bindings exist, register flow blocked on §9.4. Adapt copy + data sources without touching chrome.</p><h3 id="_3-1-marquee-status-bar" tabindex="-1">3.1. Marquee status bar <a class="header-anchor" href="#_3-1-marquee-status-bar" aria-label="Permalink to &quot;3.1. Marquee status bar&quot;">​</a></h3><p>Current wireframe:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>▣ ZKQES.ROUTER · round 2/3 · provers online: 12 · ● live · net: BASE-SEPOLIA · gas: 0.04 gwei</span></span></code></pre></div><p>Pre-launch adapted form:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>▣ ZKQES.ROUTER · round {N} of {TOTAL} · {STATE} · net: BASE-SEPOLIA</span></span></code></pre></div><p>Bindings:</p><ul><li><code>{N}</code> ← <code>status.round</code> from <code>prove.zkqes.org/ceremony/status.json</code>. Defaults to <code>0</code> when feed is unreachable or pre-feed-publication.</li><li><code>{TOTAL}</code> ← <code>status.totalRounds</code>. Phase B is currently scoped to <strong>5–10 contributors</strong> (per task <code>#8</code>, <code>circuits §11</code>); the canonical number is set when the ceremony coordinator publishes the first status JSON. Render literally what the feed says; do not hardcode.</li><li><strong>Empty-state HN-screenshot guard</strong> (marketer 2026-05-04): when both <code>{N}</code> and <code>{TOTAL}</code> are <code>0</code> (cold start, feed unreachable, or feed-published but pre-recruitment), render <code>round — of —</code> instead of <code>round 0 of 0</code>. The latter looks like a broken counter on a cold-reader screenshot; the em-dashes read as &quot;not yet populated&quot; without ambiguity.</li><li><code>{STATE}</code> ← derived from <code>status</code> via <code>lib/ceremonyStatus.ts::deriveCeremonyState()</code> (3-state, per founder Q3 lock 2026-05-04): <ul><li><code>planned</code> → <code>recruiting</code> (yellow dot, <code>var(--ua-yellow)</code>)</li><li><code>in-progress</code> → <code>ceremony-live</code> (green dot, <code>var(--ok)</code>)</li><li><code>complete</code> (and Sepolia §9.4 green) → <code>live</code> (green dot, <code>var(--ok)</code>)</li><li>feed unreachable → <code>recruiting</code> (yellow dot)</li></ul></li></ul><p>The 4-state form (<code>pre-ceremony</code> / <code>phase-b-live</code> / <code>pre-launch</code> / <code>live</code>) and the separate <code>phase: {PHASE}</code> segment from the spec&#39;s earlier draft are <strong>dropped</strong> per founder Q3 + marketer-review 2026-05-04. Reasoning: <code>pre-launch</code> undersold the ceremony milestone; <code>phase-b-live</code> was internal nomenclature; collapsing to 3 user-legible states (<code>recruiting</code> / <code>ceremony-live</code> / <code>live</code>) reads correctly to a cold visitor without project-internal context.</p><p>The &quot;gas: 0.04 gwei&quot; segment from the wireframe is <strong>dropped</strong> — gas reads need an RPC subscription and add wallet-stack dependencies the landing build deliberately excludes. The <code>phase: {PHASE}</code> placeholder that previously substituted for gas is also dropped (per the state collapse above). If founder later wants gas-on-landing, that&#39;s a follow-up that brings in a server-side gas oracle (cheap; no wallet-stack import needed).</p><h3 id="_3-2-three-column-body" tabindex="-1">3.2. Three-column body <a class="header-anchor" href="#_3-2-three-column-body" aria-label="Permalink to &quot;3.2. Three-column body&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Wireframe (post-launch)</th><th>Pre-launch adaptation</th></tr></thead><tbody><tr><td>LEFT 260px</td><td>&quot;YOU WILL NEED&quot; + &quot;PROVER MODE&quot; radios</td><td>Same prereq list (Diia + EU QTSP + Base wallet + ≥38GB RAM); <code>PROVER MODE</code> radios deferred — radios imply choosing a prover for the active register flow, which is disabled. Replace with &quot;CONTRIBUTE NOW&quot; CTA panel (recruitment-shaped).</td></tr><tr><td>MIDDLE 1fr</td><td>Tabs (Register / Rotate / Verify) active; BINDING STATEMENT field with editable wallet input + Sign-with-QES CTA</td><td>Tabs DISABLED (line-through, opacity 0.5, <code>cursor: not-allowed</code>, hover <code>title=&quot;Available after trusted setup ceremony + Sepolia testnet deploy&quot;</code>); BINDING STATEMENT shows active-voice preview copy (&quot;Holders sign a binding statement that names a wallet, and prove the signature in zk — without disclosing it.&quot;) with PRE-LAUNCH <code>ct-tag--warn</code> as the state indicator; ASCII pipeline below.</td></tr><tr><td>RIGHT 260px</td><td>&quot;RECENT BINDINGS&quot; log: timestamp / country / wallet / ✓ rows</td><td>&quot;CEREMONY ATTESTATIONS&quot; log: round / contributor / truncated attestation / ✓ rows. Source: <code>prove.zkqes.org/ceremony/status.json</code> <code>contributors[]</code>. Empty-state: &quot;awaiting first contributor (10 needed · 32 GB RAM each)&quot;.</td></tr></tbody></table><h3 id="_3-3-ctas" tabindex="-1">3.3. CTAs <a class="header-anchor" href="#_3-3-ctas" aria-label="Permalink to &quot;3.3. CTAs&quot;">​</a></h3><p>Pre-launch routes the user toward the only meaningful action available: ceremony contribution, then docs reading. Post-launch flips to register entry.</p><table tabindex="0"><thead><tr><th>CTA</th><th>Pre-launch target</th><th>Post-launch target</th></tr></thead><tbody><tr><td>Primary green button</td><td><code>/ceremony</code> (&quot;▶ Help with the ceremony&quot;)</td><td>(unchanged from wireframe) &quot;Sign with QES ▸&quot; → register flow</td></tr><tr><td>Secondary</td><td><code>https://docs.zkqes.org</code> (&quot;Read the spec ▸&quot;)</td><td><code>/verify</code> (&quot;▶ Open verifier&quot;)</td></tr></tbody></table><h3 id="_3-4-post-launch-flip" tabindex="-1">3.4. Post-launch flip <a class="header-anchor" href="#_3-4-post-launch-flip" aria-label="Permalink to &quot;3.4. Post-launch flip&quot;">​</a></h3><p>When <code>#18</code> Sepolia E2E §9.4 clears + Phase B ceremony completes, <strong>one follow-up commit</strong> swaps the pre-launch state for the wireframe&#39;s post-launch state:</p><ul><li>Re-enable Register / Rotate / Verify tabs (remove <code>DisabledTab</code> styling, point to actual route components)</li><li>Swap BINDING STATEMENT preview → live form (editable wallet input + Sign-with-QES CTA)</li><li>Rename right column &quot;CEREMONY ATTESTATIONS&quot; → &quot;RECENT BINDINGS&quot;; data source switches from status feed → on-chain event subscription (subscribed to <code>ZkqesRegistryV5_2.BindingRegistered</code> event via wagmi or viem)</li><li>Marquee state mapping: <code>complete</code> (final zkey published) → state derivation flips from <code>ceremony-live</code> → <code>live</code> once Sepolia §9.4 acceptance is confirmed at build time (<code>VITE_SEPOLIA_E2E_GREEN=1</code>). No copy-string change in the marquee itself; the change is in the derivation logic.</li></ul><p>The post-launch flip is itself a per-worker plan amendment that lands AFTER the rebrand spec is locked + implemented. It does not block the pre-launch shipping.</p><h3 id="_3-5-footer-ribbon" tabindex="-1">3.5. Footer ribbon <a class="header-anchor" href="#_3-5-footer-ribbon" aria-label="Permalink to &quot;3.5. Footer ribbon&quot;">​</a></h3><p>The wireframe&#39;s footer reads <code>FORM REVISION 04 · MAY 2026 · SUPERSEDES ALL PRIOR EDITIONS · PAGE 1 OF 1</code>. Per founder Q6 lock 2026-05-04, the production footer drops the bureaucratic-affectation framing and replaces it with the project-honest form: a 7-character truncated git SHA + ISO date, formatted as <code>&lt;7-char-SHA&gt; · YYYY-MM-DD</code>. Reads as a credibility move (zk-research audience expects build-pinning), not affectation. Bureaucratic-flavor is preserved through the rest of the chrome (civic stripe, .ct-field legends, certificate numbers); the footer specifically pivots from cosplay to provenance.</p><p>Production footer template:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{BUILD_SHA_7} · {BUILD_DATE} · zkqes.org · ?variant retired post-merge</span></span></code></pre></div><p>Bindings:</p><ul><li><code>{BUILD_SHA_7}</code> ← <code>import.meta.env.VITE_BUILD_SHA?.slice(0, 7)</code> populated at build time. The pages.yml workflow injects <code>VITE_BUILD_SHA</code> from <span><code>${{ github.sha }}</code></span> (already wired for prior surfaces; reuse). When env is unset (local <code>pnpm build</code> outside CI), fall back to literal <code>dev</code>.</li><li><code>{BUILD_DATE}</code> ← <code>import.meta.env.VITE_BUILD_DATE</code> populated as <code>YYYY-MM-DD</code> at build time. Workflow injects from <code>$(date -u +%Y-%m-%d)</code>. Fall back to literal <code>dev</code>.</li><li>The trailing <code>?variant retired post-merge</code> segment is <strong>prototype-only</strong>, removed when <code>LandingHero</code> is replaced. Post-rebrand the footer is just <code>{BUILD_SHA_7} · {BUILD_DATE} · zkqes.org</code>.</li></ul><p>The implementation reuses the styling block from the prototype:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">div</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> style</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{{ borderTop: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;1.5px solid var(--ct-ink)&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, padding: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;6px 18px&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, display: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;flex&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, gap: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">14</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, fontSize: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10.5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, color: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;var(--ct-mute)&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }}&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{buildSha} · {buildDate}&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> className</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ct-spacer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;zkqes.org&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">div</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h2 id="_4-token-grammar" tabindex="-1">4. Token grammar <a class="header-anchor" href="#_4-token-grammar" aria-label="Permalink to &quot;4. Token grammar&quot;">​</a></h2><p>The civic-terminal CSS is <strong>lifted verbatim</strong> from the wireframe bundle — <code>/tmp/zkqes-design/zk-qes-3/project/civic-terminal.css</code>, 326 lines, ported to <code>packages/web/src/styles/civic-terminal.css</code> with no token-layer refactor in this pass (per lead 2026-05-04). If broader adoption surfaces a need for refactor (e.g., a token rename for clarity, or splitting into <code>tokens.css</code> + <code>components.css</code>), that&#39;s a follow-up commit AFTER all three surfaces ship.</p><h3 id="_4-1-token-table-css-variables" tabindex="-1">4.1. Token table (CSS variables) <a class="header-anchor" href="#_4-1-token-table-css-variables" aria-label="Permalink to &quot;4.1. Token table (CSS variables)&quot;">​</a></h3><p>Locked. Don&#39;t introduce new tokens without amending this spec.</p><table tabindex="0"><thead><tr><th>Token</th><th>Value</th><th>Role</th></tr></thead><tbody><tr><td><code>--ct-paper</code></td><td><code>#d8d4c4</code></td><td>Primary panel fill (Curve-era beige/grey)</td></tr><tr><td><code>--ct-paper-2</code></td><td><code>#e6e2d2</code></td><td>Lighter inset / secondary panel fill</td></tr><tr><td><code>--ct-paper-3</code></td><td><code>#c8c4b4</code></td><td>Darker outer / panel hover state</td></tr><tr><td><code>--ct-ink</code></td><td><code>#1a1a1a</code></td><td>Primary text + frame border</td></tr><tr><td><code>--ct-ink-2</code></td><td><code>#3a352c</code></td><td>Secondary ink (hover state body text)</td></tr><tr><td><code>--ct-mute</code></td><td><code>#6b6558</code></td><td>Muted body text + dashed-rule subtle</td></tr><tr><td><code>--ct-mute-2</code></td><td><code>#8a8273</code></td><td>Tertiary mute (form labels, dim metadata)</td></tr><tr><td><code>--ct-rule</code></td><td><code>#1a1a1a</code></td><td>Solid rule + frame border</td></tr><tr><td><code>--ct-rule-soft</code></td><td><code>rgba(26,26,26,.35)</code></td><td>Dashed-rule + log-row separator</td></tr><tr><td><code>--ua-blue</code></td><td><code>#0057B7</code></td><td>Ukrainian flag blue, primary civic accent</td></tr><tr><td><code>--ua-yellow</code></td><td><code>#FFD700</code></td><td>Ukrainian flag yellow, primary civic accent</td></tr><tr><td><code>--eu-blue</code></td><td><code>#003399</code></td><td>EU flag blue, secondary civic accent</td></tr><tr><td><code>--eu-gold</code></td><td><code>#FFCC00</code></td><td>EU stars gold, secondary civic accent</td></tr><tr><td><code>--ok</code></td><td><code>#2e7d32</code></td><td>Success state (✓ marks, &quot;live&quot; dot, ok tags)</td></tr><tr><td><code>--warn</code></td><td><code>#b8860b</code></td><td>Warn state (PRE-LAUNCH tag, attention surfaces)</td></tr><tr><td><code>--err</code></td><td><code>#b00020</code></td><td>Error state (failed-attestation marks, error tags)</td></tr><tr><td><code>--hilite</code></td><td><code>#2f4a8a</code></td><td>Curve-era selection blue (active tabs, focused inputs)</td></tr><tr><td><code>--hilite-text</code></td><td><code>#f5f1e2</code></td><td>Text on <code>--hilite</code> background</td></tr></tbody></table><p>The civic-monumental palette (<code>--bone</code> / <code>--ink</code> / <code>--sovereign</code> / <code>--seal</code>) is <strong>deprecated</strong> post-amendment. Existing usages across <code>index.css</code> + <code>LandingHero.tsx</code> + <code>DocumentFooter.tsx</code> + <code>routes/index.tsx::AppRegisterLanding</code> get migrated as part of the landing implementation. The deprecation is total — no parallel-token-layer compatibility shim.</p><h3 id="_4-2-type-stack-css-custom-properties" tabindex="-1">4.2. Type stack (CSS custom properties) <a class="header-anchor" href="#_4-2-type-stack-css-custom-properties" aria-label="Permalink to &quot;4.2. Type stack (CSS custom properties)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Custom property</th><th>Value</th><th>Use case</th></tr></thead><tbody><tr><td><code>--mono</code></td><td><code>&#39;IBM Plex Mono&#39;, ui-monospace, &#39;SF Mono&#39;, Menlo, Consolas, monospace</code></td><td>All body text, code, log lines, form input, button labels</td></tr><tr><td><code>--display</code></td><td><code>&#39;VT323&#39;, &#39;IBM Plex Mono&#39;, monospace</code></td><td>Display headings (<code>&lt;h1&gt;</code>, <code>&lt;h2&gt;</code>, large numerics)</td></tr></tbody></table><p>Webfonts loaded via Google Fonts CSS @import in <code>civic-terminal.css</code>:</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@400;500;600;700&amp;family=VT323&amp;display=swap&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Implementation note: the existing landing build also @imports EB Garamond + Inter Tight. Post-rebrand both become unused; remove from <code>index.html</code> <code>&lt;link rel=&quot;preconnect&quot;&gt;</code> and any preload tags simultaneously with the landing implementation. Deferred webfonts (Inter Tight <code>wght@400;500;600</code>) carry meaningful CWV cost — removing saves ~30-50 KB initial load.</p><h3 id="_4-3-component-grammar-the-ct-namespace" tabindex="-1">4.3. Component grammar (the <code>.ct-*</code> namespace) <a class="header-anchor" href="#_4-3-component-grammar-the-ct-namespace" aria-label="Permalink to &quot;4.3. Component grammar (the `.ct-*` namespace)&quot;">​</a></h3><p>Component primitives (~12 named classes) listed below. The HTML is plain DOM elements with <code>className</code> strings; no React abstraction layer is mandated. If we extract to a <code>components/civic-terminal/</code> shared library after broader adoption, it&#39;s a follow-up.</p><table tabindex="0"><thead><tr><th>Class</th><th>Role</th><th>HTML structure example</th></tr></thead><tbody><tr><td><code>.ct</code></td><td>Base utility — sets <code>--mono</code> font, <code>--ct-fs</code> size, <code>--ct-ink</code> color, <code>--ct-paper</code> background. Wraps the page root.</td><td><code>&lt;div className=&quot;ct ct-page&quot;&gt;…&lt;/div&gt;</code></td></tr><tr><td><code>.ct-page</code></td><td>Full-page background fill + min-height.</td><td><code>&lt;div className=&quot;ct ct-page&quot;&gt;</code></td></tr><tr><td><code>.ct-panel</code></td><td>Solid border container, panel chrome.</td><td><code>&lt;div className=&quot;ct-panel&quot;&gt;…&lt;/div&gt;</code></td></tr><tr><td><code>.ct-panel--raised</code></td><td>3D raised chrome (<code>white-top + dark-bottom 1.5px borders + 1px outline</code>).</td><td><code>&lt;div className=&quot;ct-panel ct-panel--raised&quot;&gt;</code></td></tr><tr><td><code>.ct-panel--inset</code></td><td>3D inset chrome (inverse of raised).</td><td><code>&lt;div className=&quot;ct-panel ct-panel--inset&quot;&gt;</code></td></tr><tr><td><code>.ct-field</code></td><td>Dashed inner frame with floating <code>.ct-legend</code>.</td><td><code>&lt;div className=&quot;ct-field&quot;&gt;&lt;span className=&quot;ct-legend&quot;&gt;LEGEND&lt;/span&gt;…&lt;/div&gt;</code></td></tr><tr><td><code>.ct-tab</code></td><td>Curve dark-blue tab (active).</td><td><code>&lt;span className=&quot;ct-tab&quot;&gt;Register&lt;/span&gt;</code></td></tr><tr><td><code>.ct-tab--off</code></td><td>Inactive/disabled tab.</td><td><code>&lt;span className=&quot;ct-tab ct-tab--off&quot;&gt;…&lt;/span&gt;</code></td></tr><tr><td><code>.ct-btn</code></td><td>Default button with raised chrome.</td><td><code>&lt;button className=&quot;ct-btn&quot;&gt;…&lt;/button&gt;</code></td></tr><tr><td><code>.ct-btn--primary</code></td><td>Curve &quot;green Sell&quot; primary button (<code>#6cd960</code>).</td><td><code>&lt;button className=&quot;ct-btn ct-btn--primary&quot;&gt;…&lt;/button&gt;</code></td></tr><tr><td><code>.ct-btn--ua</code></td><td>UA-yellow background, UA-blue text.</td><td><code>&lt;button className=&quot;ct-btn ct-btn--ua&quot;&gt;…&lt;/button&gt;</code></td></tr><tr><td><code>.ct-btn--eu</code></td><td>EU-blue background, EU-gold text.</td><td><code>&lt;button className=&quot;ct-btn ct-btn--eu&quot;&gt;…&lt;/button&gt;</code></td></tr><tr><td><code>.ct-btn--ghost</code></td><td>Transparent background, ink border.</td><td><code>&lt;button className=&quot;ct-btn ct-btn--ghost&quot;&gt;…&lt;/button&gt;</code></td></tr><tr><td><code>.ct-btn--sm</code> / <code>--lg</code></td><td>Size modifiers (11px / 16px font).</td><td><code>&lt;button className=&quot;ct-btn ct-btn--lg&quot;&gt;…&lt;/button&gt;</code></td></tr><tr><td><code>.ct-input</code></td><td>Form input with <code>--hilite</code> background + <code>--hilite-text</code> (Curve-era selection-color form fill).</td><td><code>&lt;input className=&quot;ct-input&quot; /&gt;</code></td></tr><tr><td><code>.ct-input--paper</code></td><td>Paper-background variant of <code>.ct-input</code>.</td><td><code>&lt;input className=&quot;ct-input ct-input--paper&quot; /&gt;</code></td></tr><tr><td><code>.ct-civic-stripe</code></td><td>Four-bar civic stripe (UA-blue / UA-yellow / EU-blue / EU-gold).</td><td><code>&lt;div className=&quot;ct-civic-stripe&quot;&gt;&lt;i/&gt;&lt;i/&gt;&lt;i/&gt;&lt;i/&gt;&lt;/div&gt;</code></td></tr><tr><td><code>.ct-flag-ua</code></td><td>Ukrainian flag glyph (16×24, two-bar).</td><td><code>&lt;div className=&quot;ct-flag-ua&quot;&gt;&lt;i/&gt;&lt;i/&gt;&lt;/div&gt;</code></td></tr><tr><td><code>.ct-flag-eu</code></td><td>EU flag glyph (16×24, blue with <code>★</code>).</td><td><code>&lt;div className=&quot;ct-flag-eu&quot;&gt;★&lt;/div&gt;</code></td></tr><tr><td><code>.ct-tag</code></td><td>Tiny pill / chip (10.5px, uppercase, 0.06em letter-spacing).</td><td><code>&lt;span className=&quot;ct-tag ct-tag--ok&quot;&gt;…&lt;/span&gt;</code></td></tr><tr><td><code>.ct-tag--ua</code> / <code>--eu</code> / <code>--ok</code> / <code>--warn</code> / <code>--err</code></td><td>Color variants.</td><td>(combine)</td></tr><tr><td><code>.ct-seal</code></td><td>96×96 round civic seal at -6° rotation, <code>&lt;b&gt;</code> for bold inner.</td><td><code>&lt;div className=&quot;ct-seal&quot;&gt;&lt;div&gt;&lt;b&gt;zkQES&lt;/b&gt;QUALIFIED · 2026&lt;/div&gt;&lt;/div&gt;</code></td></tr><tr><td><code>.ct-row</code> / <code>.ct-row-h</code> / <code>.ct-grid-2</code> / <code>.ct-grid-3</code></td><td>Layout helpers (vertical rows, horizontal flex, 2-col / 3-col grids).</td><td><code>&lt;div className=&quot;ct-row-h&quot;&gt;…&lt;/div&gt;</code></td></tr><tr><td><code>.ct-stack</code></td><td>Vertical flex with <code>var(--ct-gap)</code> gap.</td><td><code>&lt;div className=&quot;ct-stack&quot;&gt;…&lt;/div&gt;</code></td></tr><tr><td><code>.ct-spacer</code></td><td><code>flex: 1</code> filler.</td><td><code>&lt;span className=&quot;ct-spacer&quot; /&gt;</code></td></tr><tr><td><code>.ct-divider</code> / <code>.ct-divider--dashed</code></td><td>Solid / dashed top-border row.</td><td><code>&lt;div className=&quot;ct-divider--dashed&quot; /&gt;</code></td></tr><tr><td><code>.ct-cert-no</code></td><td>Cert-number text style (10.5px, 0.12em letter-spacing).</td><td><code>&lt;span className=&quot;ct-cert-no&quot;&gt;CERT. NO. ZK·2026·00001&lt;/span&gt;</code></td></tr><tr><td><code>.ct-kicker</code></td><td>Eyebrow text (10.5px, 0.18em letter-spacing, uppercase, <code>--ct-mute</code>).</td><td><code>&lt;div className=&quot;ct-kicker&quot;&gt;…&lt;/div&gt;</code></td></tr><tr><td><code>.ct-ascii</code> / <code>.ct-ascii--dense</code></td><td>Pre-formatted ASCII art (11px / 9.5px line-height 1.05/1.0).</td><td><code>&lt;pre className=&quot;ct-ascii&quot;&gt;…&lt;/pre&gt;</code></td></tr><tr><td><code>.ct-radio</code> / <code>.ct-check</code></td><td>Form-y bits: <code>( )</code> / <code>(•)</code> radios; <code>[ ]</code> / <code>[x]</code> checkboxes (text-based, not native).</td><td><code>&lt;label className=&quot;ct-radio on&quot;&gt;&lt;span className=&quot;b&quot; /&gt;&lt;span&gt;…&lt;/span&gt;&lt;/label&gt;</code></td></tr><tr><td><code>.ct-log</code></td><td>Log-line container (11.5px). With <code>.t</code> / <code>.ok</code> / <code>.warn</code> / <code>.err</code> / <code>.b</code> modifiers for timestamp / status / bold.</td><td><code>&lt;div className=&quot;ct-log&quot;&gt;&lt;div className=&quot;ct-row-h&quot;&gt;&lt;span className=&quot;t&quot;&gt;12:04&lt;/span&gt;…&lt;/div&gt;&lt;/div&gt;</code></td></tr><tr><td><code>.ct-corners</code></td><td>Decorative <code>+</code> glyphs at top-left + bottom-right.</td><td><code>&lt;div className=&quot;ct-corners&quot;&gt;…&lt;/div&gt;</code></td></tr><tr><td><code>.ct-link</code></td><td>Underlined link, <code>--ua-blue</code> color, pointer cursor.</td><td><code>&lt;a className=&quot;ct-link&quot;&gt;…&lt;/a&gt;</code></td></tr></tbody></table><h3 id="_4-4-tweak-attributes-data-on-root" tabindex="-1">4.4. Tweak attributes (data-* on <code>:root</code>) <a class="header-anchor" href="#_4-4-tweak-attributes-data-on-root" aria-label="Permalink to &quot;4.4. Tweak attributes (data-* on `:root`)&quot;">​</a></h3><p>The CSS supports three runtime tweak axes via data attrs on <code>:root</code>. Implementation includes a default in source (<code>medium</code> / <code>regular</code>); runtime swap is OPTIONAL for landing/docs but should be wired so future internal-tooling tweaks don&#39;t need code edits.</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Values</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td><code>data-density</code></td><td><code>dense</code> / <code>regular</code> / <code>sparse</code></td><td><code>regular</code></td><td>Padding + gap + base font-size scaling</td></tr><tr><td><code>data-chrome</code></td><td><code>minimal</code> / <code>medium</code> / <code>thick</code></td><td><code>medium</code></td><td>Border weight + dashed-stroke pattern</td></tr></tbody></table><p>A third axis from the wireframe (<code>data-palette</code> for <code>blended</code> / <code>ua</code> / <code>eu</code> / <code>bw</code>) is <strong>dropped from production</strong> — palette is locked to the EU variant per founder direction (already applied in the wireframe via the <code>palette: &#39;eu&#39;</code> default). The blended/ua/bw variants are review-time-only artifacts.</p><h2 id="_5-accessibility-mitigations" tabindex="-1">5. Accessibility mitigations <a class="header-anchor" href="#_5-accessibility-mitigations" aria-label="Permalink to &quot;5. Accessibility mitigations&quot;">​</a></h2><p>VT323 + IBM Plex Mono shifts the type stack from a serif/sans/mono mix to all-monospace. That carries readability + accessibility risk that the wireframe (single-page artboards reviewed in design canvas) doesn&#39;t surface but a real shipping landing does.</p><h3 id="_5-1-vt323-size-band-caveats" tabindex="-1">5.1. VT323 size-band caveats <a class="header-anchor" href="#_5-1-vt323-size-band-caveats" aria-label="Permalink to &quot;5.1. VT323 size-band caveats&quot;">​</a></h3><p>VT323 is a bitmap-style display font. Legible sizes from the wireframe inspection: 22 / 26 / 28 / 36 / 44 / 64px. Below ~18px the bitmap renders fuzzy on most screens. Above ~72px it becomes blocky. Locked usage:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Element</th><th>px</th><th>Token reference</th></tr></thead><tbody><tr><td>Hero</td><td><code>&lt;h1&gt;</code> lead statement</td><td>64</td><td><code>font-family: var(--display)</code> + inline <code>fontSize: 64</code></td></tr><tr><td>Section</td><td><code>&lt;h2&gt;</code> section heading</td><td>36</td><td><code>var(--display)</code> + <code>fontSize: 36</code></td></tr><tr><td>Subsection</td><td><code>&lt;h3&gt;</code> minor heading</td><td>28</td><td><code>var(--display)</code> + <code>fontSize: 28</code></td></tr><tr><td>Logo</td><td>site header brand</td><td>26</td><td><code>var(--display)</code> + <code>fontSize: 26</code></td></tr><tr><td>Step number</td><td><code>STEP 01</code> numeric</td><td>26</td><td>(where used)</td></tr></tbody></table><p>Body text, log lines, form input, button labels: <strong>always <code>--mono</code></strong> (IBM Plex Mono), never VT323. Don&#39;t use VT323 below 22px; if a smaller display element is needed, fall through to <code>--mono</code> weight 600 with letter-spacing.</p><h3 id="_5-2-mono-everywhere-readability-tax" tabindex="-1">5.2. Mono-everywhere readability tax <a class="header-anchor" href="#_5-2-mono-everywhere-readability-tax" aria-label="Permalink to &quot;5.2. Mono-everywhere readability tax&quot;">​</a></h3><p>IBM Plex Mono at 13px (the spec&#39;s <code>--ct-fs</code> regular) is dense for paragraphs of long-form copy. Mitigations:</p><ul><li><strong>Constrain max-width on body paragraphs to 65ch.</strong> Mono characters are wider than proportional, so 65ch (~520px at 13px) is the comfortable line-length tier.</li><li><strong>Use <code>line-height: 1.55</code></strong> for paragraph copy (current CSS sets 1.45 globally; bump to 1.55 specifically for <code>&lt;p&gt;</code> inside body content; leave 1.45 for compact log/table rows).</li><li><strong>Break long copy into legend-fielded cards.</strong> The <code>.ct-field</code> with <code>.ct-legend</code> floating label visually chunks paragraphs into bureaucratic-form chunks; reading 4 lines under a legend is easier than reading 12 lines flat. Reuse aggressively in the docs rebrand especially.</li><li><strong>Use <code>--ct-mute</code> for paragraph copy that&#39;s optional reading.</strong> Lower-contrast text reads as &quot;supporting info&quot; and visitors skip past without effort. Critical info stays at <code>--ct-ink</code> (full contrast).</li><li><strong>No paragraphs longer than 4 sentences in landing copy.</strong> Docs paragraphs can be longer (different audience), but landing visitors scan; 4 sentences is the upper bound before cognitive cost spikes.</li></ul><h3 id="_5-3-contrast-checks-wcag" tabindex="-1">5.3. Contrast checks (WCAG) <a class="header-anchor" href="#_5-3-contrast-checks-wcag" aria-label="Permalink to &quot;5.3. Contrast checks (WCAG)&quot;">​</a></h3><p>Required AA-level contrast ratio for body text: <strong>4.5:1</strong>. AAA is <strong>7:1</strong>. Tested against <code>--ct-paper</code> background (#d8d4c4):</p><table tabindex="0"><thead><tr><th>Foreground</th><th>Ratio against <code>#d8d4c4</code></th><th>WCAG</th></tr></thead><tbody><tr><td><code>--ct-ink</code> (#1a1a1a)</td><td><strong>9.83:1</strong></td><td>AAA ✓</td></tr><tr><td><code>--ct-mute</code> (#6b6558)</td><td><strong>3.66:1</strong></td><td>AA fail for body; OK for 18px+ large text only</td></tr><tr><td><code>--ua-blue</code> (#0057B7) on paper</td><td><strong>5.12:1</strong></td><td>AA ✓</td></tr><tr><td><code>--ok</code> (#2e7d32) on paper</td><td><strong>3.84:1</strong></td><td>AA fail for body; OK for 18px+</td></tr><tr><td><code>--warn</code> (#b8860b) on paper</td><td><strong>2.96:1</strong></td><td>AA FAIL — bump to <code>--ct-ink</code> for body text accompanied by <code>--warn</code> background</td></tr><tr><td><code>--err</code> (#b00020) on paper</td><td><strong>6.18:1</strong></td><td>AA ✓</td></tr><tr><td>White (<code>#fff</code>) on <code>--hilite</code> (#2f4a8a)</td><td><strong>8.79:1</strong></td><td>AAA ✓</td></tr><tr><td><code>--ua-yellow</code> (#FFD700) on <code>--ua-blue</code> (#0057B7)</td><td><strong>6.96:1</strong></td><td>AA ✓</td></tr><tr><td><code>--eu-gold</code> (#FFCC00) on <code>--eu-blue</code> (#003399)</td><td><strong>9.13:1</strong></td><td>AAA ✓</td></tr></tbody></table><p><strong>Hard rules from the contrast audit:</strong></p><ul><li><code>--ct-mute</code> is only used for ≥18px large text, captions, optional metadata. Never primary body.</li><li><code>--ok</code> (#2e7d32) on paper is only used for ≥18px (large status marks like ✓ at 18px+). Body text status: stick with <code>--ct-ink</code> and rely on positional grammar (e.g., the <code>.ok</code> modifier on log lines bumps the size to 14px+ and the contrast crosses AA).</li><li><code>--warn</code> (#b8860b) is <strong>never</strong> on <code>--ct-paper</code>. The <code>.ct-tag--warn</code> background is <code>#f3e1b3</code> (which has 17.3:1 against <code>--ct-ink</code>), so warn-tagged text uses ink-on-warn-bg.</li><li>Active form input: <code>--hilite</code> background (#2f4a8a) with <code>--hilite-text</code> (#f5f1e2) — already 8.79:1, AAA. Disabled form input: <code>--ct-paper-2</code> (#e6e2d2) background with <code>--ct-mute</code> text — 4.21:1, AA at 14px+. Don&#39;t render disabled at smaller font.</li></ul><h3 id="_5-4-keyboard-screen-reader" tabindex="-1">5.4. Keyboard + screen reader <a class="header-anchor" href="#_5-4-keyboard-screen-reader" aria-label="Permalink to &quot;5.4. Keyboard + screen reader&quot;">​</a></h3><ul><li>The disabled tabs (Register / Rotate / Verify) ship with <code>aria-disabled=&quot;true&quot;</code> and the <code>title</code> attribute repeated as <code>aria-label</code>. Screen readers announce &quot;Register, dimmed, Available after Phase B ceremony + Sepolia §9.4&quot;. Keyboard focus skips them (test: Tab from &quot;Help with the ceremony&quot; should skip directly to &quot;Open verifier&quot;, not stop on disabled tabs).</li><li>ASCII art is wrapped in <code>&lt;pre aria-hidden=&quot;true&quot;&gt;</code> — meaningful to sighted users only; the surrounding <code>&lt;div&gt;</code> has visible-text descriptions for each pipeline stage as fallback.</li><li>The <code>.ct-civic-stripe</code> is <code>aria-hidden=&quot;true&quot;</code> (decorative).</li><li>The <code>.ct-flag-ua</code> and <code>.ct-flag-eu</code> glyphs have <code>title</code> attributes (<code>Україна</code>, <code>EU</code>); add explicit <code>aria-label=&quot;Ukrainian flag&quot;</code> / <code>aria-label=&quot;EU flag&quot;</code> on render.</li><li>The <code>.ct-seal</code> is decorative (<code>aria-hidden=&quot;true&quot;</code>).</li><li>Marquee status bar: live updates announced via <code>&lt;div aria-live=&quot;polite&quot;&gt;</code>. Don&#39;t use <code>aria-live=&quot;assertive&quot;</code> — round transitions don&#39;t need to interrupt screen reader speech.</li></ul><h3 id="_5-5-reduced-motion" tabindex="-1">5.5. Reduced-motion <a class="header-anchor" href="#_5-5-reduced-motion" aria-label="Permalink to &quot;5.5. Reduced-motion&quot;">​</a></h3><p>The CSS has no animation currently. If we add any (e.g., a scrolling marquee), wrap the animation in <code>@media (prefers-reduced-motion: no-preference) { … }</code> so reduced-motion users get the static state.</p><h2 id="_6-brand-md-amendment-scope" tabindex="-1">6. BRAND.md amendment scope <a class="header-anchor" href="#_6-brand-md-amendment-scope" aria-label="Permalink to &quot;6. BRAND.md amendment scope&quot;">​</a></h2><p>Three new sections appended to <code>BRAND.md</code> (between current §5 &quot;Domains&quot; and §6 &quot;Defensive registrations&quot;). No existing sections modified.</p><h3 id="_6-1-new-section-visual-language" tabindex="-1">6.1. New section: &quot;Visual language&quot; <a class="header-anchor" href="#_6-1-new-section-visual-language" aria-label="Permalink to &quot;6.1. New section: &quot;Visual language&quot;&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Visual language</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">The visual identity is </span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**civic-terminal**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: Curve.fi-era panel chrome</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(beige/grey paper, raised/inset 3D borders, dashed inner frames with</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">floating legends) crossed with Ukraine + EU civic-document signals</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(four-bar civic stripe, official-form letterhead structure,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">embossed seals). Pure monospace type. Heavy use of ASCII art.</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">The aesthetic positions the project as bureaucratic-credible (this</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">is a thing that interfaces with real-world legal trust services</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">under eIDAS and Ukrainian DSP law) AND engineering-credible: the</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">system is built on Groth16/Circom against real eIDAS trust-service</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">infrastructure.</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Date locked:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 2026-05-04 (replaces the prior civic-monumental</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">direction shipped 2026-05-03 in #60). Decision reference:</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`docs/superpowers/specs/2026-05-04-zkqes-civic-terminal-rebrand-design.md`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Wireframe reference:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Founder-curated Claude Design bundle, variant D</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(&quot;Curve router · dense&quot;). The marquee + 3-column data-grid layout is</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">the canonical home shape; other surfaces inherit the same chrome</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">grammar at appropriate density.</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Subdomain consistency:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> All three subdomains (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`zkqes.org`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`docs.zkqes.org`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`app.zkqes.org`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) consume the same token layer</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`packages/web/src/styles/civic-terminal.css`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">). Cross-subdomain</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">visual drift is a regression.</span></span></code></pre></div><h3 id="_6-2-new-section-type-stack" tabindex="-1">6.2. New section: &quot;Type stack&quot; <a class="header-anchor" href="#_6-2-new-section-type-stack" aria-label="Permalink to &quot;6.2. New section: &quot;Type stack&quot;&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Type stack</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Role | Typeface | Weights | CSS variable |</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">|---|---|---|---|</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Display (h1, h2, h3, large numerics, brand mark) | VT323 | 400 only | </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`--display`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> |</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Body (paragraphs, log lines, form input, button labels, code) | IBM Plex Mono | 400, 500, 600, 700 | </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`--mono`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> |</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Webfonts loaded via Google Fonts CDN with </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">`font-display: swap`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">```html</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preconnect&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://fonts.googleapis.com&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> crossorigin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;preconnect&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://fonts.gstatic.com&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> crossorigin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">link</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@400;500;600;700&amp;family=VT323&amp;display=swap&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;stylesheet&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  crossorigin</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/&gt;</span></span></code></pre></div><p><code>crossorigin</code> is set on every <code>&lt;link&gt;</code> so the browser performs a CORS fetch (matches the server&#39;s <code>Access-Control-Allow-Origin: *</code> and deduplicates against later font-file CORS requests). <code>font-display: swap</code> is encoded in the URL query (<code>&amp;display=swap</code>) and produces a brief fallback-font flash on first paint instead of a blocked-render window.</p><p><code>integrity</code> Subresource Integrity hashes are NOT used: Google Fonts does not publish stable hashes for the dynamically-generated CSS (content varies by user-agent). Self-hosting the fonts (which would let us pin SRI) is a follow-up polish pass post-adoption, not load-bearing for the v0.6.x recruitment window. Per founder Q1 lock 2026-05-04.</p><p>VT323 size band: 22-72px. Below 22px VT323 renders fuzzy; below 18px do not use VT323 — fall through to <code>--mono</code> 600-weight. Body copy constrained to ≤65ch line length to mitigate monospace readability tax.</p><p>The prior civic-monumental type stack (EB Garamond + Inter Tight + JetBrains Mono) is deprecated as of 2026-05-04. Existing references in <code>packages/web/index.html</code> <code>&lt;link&gt;</code> preconnects must be removed <strong>in the same commit that adds VT323 + Plex Mono</strong> — atomic transition, no dead-preconnect window. Per lead Q2 lock 2026-05-04.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>\n<span class="line"><span>### 6.3. New section: &quot;Component grammar&quot;</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>```markdown</span></span>\n<span class="line"><span>## Component grammar</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>The visual surface is built from a stable set of class-based</span></span>\n<span class="line"><span>primitives. These are CSS classes consumed by JSX className</span></span>\n<span class="line"><span>strings; they are NOT React components by default. If a future</span></span>\n<span class="line"><span>broader adoption surfaces a need for component extraction, that&#39;s</span></span>\n<span class="line"><span>a follow-up.</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>**Source of truth:** `packages/web/src/styles/civic-terminal.css`.</span></span>\n<span class="line"><span>The class namespace is stable; new primitives require a BRAND.md</span></span>\n<span class="line"><span>amendment + a corresponding entry in the rebrand spec</span></span>\n<span class="line"><span>(`docs/superpowers/specs/2026-05-04-zkqes-civic-terminal-rebrand-design.md`</span></span>\n<span class="line"><span>§4.3).</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>**Token table:** see same spec §4.1 for the full CSS-variable</span></span>\n<span class="line"><span>reference (--ct-paper / --ct-ink / --ua-blue / --ua-yellow /</span></span>\n<span class="line"><span>--eu-blue / --eu-gold / --ok / --warn / --err / --hilite + 5 more).</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>**Primary primitives:**</span></span>\n<span class="line"><span>- `.ct-panel` (solid panel chrome) + `.ct-panel--raised` /</span></span>\n<span class="line"><span>  `.ct-panel--inset` (3D variants)</span></span>\n<span class="line"><span>- `.ct-field` (dashed inner frame) + `.ct-legend` (floating label)</span></span>\n<span class="line"><span>- `.ct-tab` / `.ct-tab--off` (Curve-era tabs)</span></span>\n<span class="line"><span>- `.ct-btn` + variants (`--primary`, `--ua`, `--eu`, `--ghost`,</span></span>\n<span class="line"><span>  `--sm`, `--lg`)</span></span>\n<span class="line"><span>- `.ct-civic-stripe` (4-bar UA + EU stripe — decorative,</span></span>\n<span class="line"><span>  `aria-hidden`)</span></span>\n<span class="line"><span>- `.ct-flag-ua` / `.ct-flag-eu` (16×24 glyphs)</span></span>\n<span class="line"><span>- `.ct-tag` + variants (--ua / --eu / --ok / --warn / --err)</span></span>\n<span class="line"><span>- `.ct-seal` (rotated 96×96 civic seal)</span></span>\n<span class="line"><span>- `.ct-cert-no` / `.ct-kicker` (cert-number / eyebrow text styles)</span></span>\n<span class="line"><span>- `.ct-ascii` / `.ct-ascii--dense` (ASCII art containers)</span></span>\n<span class="line"><span>- `.ct-log` / `.ct-row` / `.ct-row-h` / `.ct-stack` /</span></span>\n<span class="line"><span>  `.ct-grid-2` / `.ct-grid-3` (layout helpers)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>The spec&#39;s §4.3 lists the full set with HTML structure examples.</span></span>\n<span class="line"><span>Adding a new primitive is a BRAND.md amendment + a CSS edit + a</span></span>\n<span class="line"><span>spec entry.</span></span></code></pre></div><h3 id="_6-4-insertion-point" tabindex="-1">6.4. Insertion point <a class="header-anchor" href="#_6-4-insertion-point" aria-label="Permalink to &quot;6.4. Insertion point&quot;">​</a></h3><p>The three sections insert in <code>BRAND.md</code> between current <code>## Domains</code> and current <code>## Defensive registrations</code>. So new TOC ordering:</p><ol><li>Name</li><li>What this brand REVERSED</li><li>How to write about the project</li><li>Frozen consensus bytes (NOT branding)</li><li>Domains</li><li><strong>Visual language</strong> (NEW)</li><li><strong>Type stack</strong> (NEW)</li><li><strong>Component grammar</strong> (NEW)</li><li>Defensive registrations</li><li>When this document changes</li></ol><h2 id="_7-sequencing-rationale" tabindex="-1">7. Sequencing rationale <a class="header-anchor" href="#_7-sequencing-rationale" aria-label="Permalink to &quot;7. Sequencing rationale&quot;">​</a></h2><p>Lead 2026-05-04 directive: <strong>sequential</strong> BRAND → landing → docs → app, NOT parallel.</p><h3 id="_7-1-brand-md-amendment-first" tabindex="-1">7.1. BRAND.md amendment first <a class="header-anchor" href="#_7-1-brand-md-amendment-first" aria-label="Permalink to &quot;7.1. BRAND.md amendment first&quot;">​</a></h3><p>Reasons:</p><ul><li>BRAND.md is the source-of-truth for token names, type stack, component grammar. Implementation references it (the per-worker plan cites <code>BRAND.md §6.1</code> etc.).</li><li>Founder must approve the amendment in isolation. A combined &quot;BRAND + landing implementation&quot; PR hides the brand pivot in a 600-line React diff and makes future audits harder (<code>git log --follow BRAND.md</code> should show the brand changes as discrete events, not embedded in feature commits).</li></ul><p>Branch: <code>chore/brand-civic-terminal</code> from main. Single commit. Founder reviews + merges. Then landing implementation branches from updated main.</p><h3 id="_7-2-landing-first-beats-landing-docs-parallel" tabindex="-1">7.2. Landing-first beats landing+docs-parallel <a class="header-anchor" href="#_7-2-landing-first-beats-landing-docs-parallel" aria-label="Permalink to &quot;7.2. Landing-first beats landing+docs-parallel&quot;">​</a></h3><p>Reasons:</p><ul><li>The token layer ports verbatim into <code>packages/web/src/styles/civic-terminal.css</code>. Both landing + docs consume that file. If landing implementation surfaces a need for token-layer amendment (e.g., a missing color or a chrome rule that doesn&#39;t translate), we learn it once and fix it before docs starts consuming. Parallel = two surfaces racing on possibly-changing tokens = wasted work.</li><li>Landing has more visual variety (variant D&#39;s three columns + marquee + ASCII pipeline + ledger) than docs (which is mostly text-on-paper-with-chrome). Landing forces all primitives through their paces; docs is a token consumer with fewer novel uses.</li><li>Landing is the recruitment surface, time-pressured. Docs is reference, not time-pressured. Parallel would slip landing for docs&#39;s sake.</li></ul><p>Branch: <code>feat/civic-terminal-landing</code> from main (post-BRAND-merge). ~3-4 days. Single PR for review.</p><h3 id="_7-3-docs-after-landing" tabindex="-1">7.3. Docs after landing <a class="header-anchor" href="#_7-3-docs-after-landing" aria-label="Permalink to &quot;7.3. Docs after landing&quot;">​</a></h3><p>Branch: <code>feat/civic-terminal-docs</code> from main (post-landing-merge). ~2 days. The <code>docs/.vitepress/theme/custom.css</code> rewrite is the bulk of the work — rebind <code>--vp-c-*</code> tokens against civic-terminal palette, swap webfonts, mirror landing&#39;s <code>.ct-tab</code> grammar in nav + sidebar.</p><h3 id="_7-4-app-deferred-to-§9-4" tabindex="-1">7.4. App deferred to §9.4 <a class="header-anchor" href="#_7-4-app-deferred-to-§9-4" aria-label="Permalink to &quot;7.4. App deferred to §9.4&quot;">​</a></h3><p>The app rebrand (<code>VITE_TARGET=app</code> build, <code>app.zkqes.org</code> deploy) ports the same chrome to register / rotate / verify / account / escrow flows. ~30 React components touched. The implementation branch waits for <code>#18</code> Sepolia E2E §9.4 to clear — the register flow itself isn&#39;t deployable pre-§9.4, so rebranding it now is wasted work (the live URL doesn&#39;t exist; visual review can&#39;t happen against real app behavior).</p><p>The app spec + plan can land NOW, in this same dispatch (§4 of the orchestration plan). Implementation branch waits.</p><h3 id="_7-5-concurrent-with-62-wave-2-phase-a-recruitment" tabindex="-1">7.5. Concurrent with #62 wave-2 + Phase A recruitment <a class="header-anchor" href="#_7-5-concurrent-with-62-wave-2-phase-a-recruitment" aria-label="Permalink to &quot;7.5. Concurrent with #62 wave-2 + Phase A recruitment&quot;">​</a></h3><p>Per lead 2026-05-04: zkqes.org root DNS is live (#62 wave-1 done); rebrand work proceeds in parallel with #62 wave-2 (app + docs subdomain DNS) and founder&#39;s Phase A ceremony recruitment. Recruitment does NOT wait for variant D — the protocol pitch carries recruitment, not the chrome.</p><h2 id="_8-out-of-scope" tabindex="-1">8. Out of scope <a class="header-anchor" href="#_8-out-of-scope" aria-label="Permalink to &quot;8. Out of scope&quot;">​</a></h2><ul><li><strong>VS Code / IntelliJ extensions</strong> — none exist</li><li><strong>README / GitHub-side markdown rendering</strong> — out of brand control (GitHub renders with their CSS)</li><li><strong>Email templates</strong> — no email surface</li><li><strong>Marketing PDF / X-thread / HN graphics</strong> — handled by marketer; spec lists the CSS path so marketer can pull tokens</li><li><strong>Backend admin UIs</strong> — none exist; ceremony coordinator is markdown + JSON</li><li><strong>Token-layer refactor</strong> — verbatim port for this pass; refactor (e.g., split into <code>tokens.css</code> + <code>components.css</code>) is a follow-up after all three surfaces ship</li><li><strong>Component-extraction to React library</strong> — inline JSX with className strings is sufficient; if broader patterns emerge, extract in a follow-up</li><li><strong>Civic-monumental compatibility shim</strong> — total deprecation, no parallel-token-layer</li><li><strong>Internationalization of new copy</strong> — UA + EN parity is invariant #2 in <code>packages/web/CLAUDE.md</code>. The landing implementation MUST add new keys to both <code>i18n/en.json</code> and <code>i18n/uk.json</code> in the same commit; this is per-worker plan responsibility, not spec-level.</li><li><strong>Performance budgets beyond the existing landing build</strong> — landing chunk size baseline is 2.52 MB (per #60); the rebrand should land within +10% (≤2.77 MB). If the implementation surfaces a larger blow-out, surface to lead before merge.</li></ul><h2 id="_9-risks-mitigations" tabindex="-1">9. Risks + mitigations <a class="header-anchor" href="#_9-risks-mitigations" aria-label="Permalink to &quot;9. Risks + mitigations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk</th><th>Likelihood</th><th>Impact</th><th>Mitigation</th></tr></thead><tbody><tr><td>VT323 reads as &quot;ironic / cosplay&quot; not &quot;engineering / civic&quot;</td><td>Medium</td><td>High</td><td>Founder pre-approved variant D from wireframe review; the descriptor copy (&quot;a zero-knowledge proof of a qualified electronic signature&quot;) provides the seriousness anchor that the chrome alone might not. Marketer review pass catches if copy doesn&#39;t carry.</td></tr><tr><td>Mono-everywhere body copy reads slow / heavy</td><td>High</td><td>Medium</td><td>Mitigations in §5.2: 65ch max-width, 1.55 line-height for paragraphs, <code>.ct-field</code> chunking, <code>--ct-mute</code> for optional reading, ≤4-sentence paragraph rule on landing. Real-browser preview during landing implementation surfaces specific paragraphs that need rework.</td></tr><tr><td>Win98 raised/inset chrome reads as &quot;retro novelty&quot;</td><td>Medium</td><td>Medium</td><td>The chrome subtlety knob is <code>data-chrome=&quot;medium&quot;</code> (default) — minimal/medium/thick gives founder a runtime dial without a re-implementation. If post-launch user feedback skews &quot;novelty,&quot; dial down to <code>minimal</code> via a one-line root-attr edit.</td></tr><tr><td>BRAND.md deprecation invalidates copy in marketer launch drafts</td><td>Low</td><td>Medium</td><td>Marketer review pass on the spec before BRAND.md amendment lands. Copy that uses old palette descriptors gets rewritten in the same wave.</td></tr><tr><td><code>civic-terminal.css</code> Google Fonts @import slows initial paint</td><td>Medium</td><td>Low</td><td>Google Fonts CDN is a stable + cacheable resource; preconnect tags in <code>index.html</code> mitigate connection cost. Alternative: self-host fonts via <code>vite-plugin-fonts</code> (~80 KB added to bundle, but eliminates a 3rd-party dependency). Spec defers self-hosting to a follow-up unless founder explicitly asks.</td></tr><tr><td>Status feed schema drift breaks marquee or attestations</td><td>Low</td><td>High</td><td><code>lib/ceremonyStatus.ts</code> is the consumer + locks the shape (<code>CeremonyStatusPayload</code> interface). Admin-script-side respects the same shape (per the existing <code>// Don&#39;t change types here without coordinating</code> comment). Any feed shape change requires an admin-script + frontend co-edit.</td></tr><tr><td><code>data-chrome</code> / <code>data-density</code> runtime swap is unused → bit-rot</td><td>Low</td><td>Low</td><td>Wire it in production; expose via a hidden URL param <code>?ctChrome=thick</code> for internal testing. Founder/lead can dial without a rebuild.</td></tr><tr><td>App rebrand drifts from landing during the §9.4 wait</td><td>Medium</td><td>High</td><td>App spec + plan land NOW (§7.4), in this dispatch wave. When §9.4 clears, implementation reads the locked plan; visual cohesion is locked at spec time, not implementation time.</td></tr><tr><td>Pre-launch empty-state copy reads as &quot;broken&quot; not &quot;pre-launch&quot;</td><td>Medium</td><td>Medium</td><td>Explicit &quot;RECRUITING&quot; / &quot;AWAITING FIRST CONTRIBUTOR&quot; copy makes the state legible. PRE-LAUNCH <code>.ct-tag--warn</code> on the binding-statement field tells visitors &quot;this isn&#39;t broken, this is a known stage.&quot;</td></tr><tr><td>Cached visitors carrying old EB Garamond webfont → flash of unstyled content</td><td>Low</td><td>Low</td><td>First-paint cost is one-time per visitor; caches expire on next dep update. Acceptable.</td></tr><tr><td>Founder later wants to revert to civic-monumental</td><td>Low</td><td>High</td><td>The full file diff is reversible — <code>git revert</code> of the merge commits restores the prior state. Worktree retention strategy: keep the prior branches (<code>feat/v5_3-zkqes-d-prototype @ c242778</code>, <code>chore/civic-terminal-spec @ this</code>) in repo until founder confirms post-launch.</td></tr></tbody></table><h2 id="_10-open-questions" tabindex="-1">10. Open questions <a class="header-anchor" href="#_10-open-questions" aria-label="Permalink to &quot;10. Open questions&quot;">​</a></h2><p>All Q1-Q3 and Q6 were resolved 2026-05-04 (lead Q1+Q2; founder Q3+Q6 routed via marketer review). Q4 deferred per spec; Q5 locked at spec time.</p><ul><li><strong>Q1. RESOLVED 2026-05-04 (lead).</strong> Self-host webfonts vs Google Fonts CDN? <strong>CDN with <code>font-display: swap</code> + <code>crossorigin</code> on every <code>&lt;link&gt;</code>. SRI integrity hashes deferred (Google Fonts doesn&#39;t publish stable hashes for dynamically-generated CSS).</strong> Self-hosting is a follow-up polish pass post-adoption, NOT load-bearing for the v0.6.x recruitment window. Implementation reflected in §6.2 Type Stack and §4.2 type custom-property reference.</li><li><strong>Q2. RESOLVED 2026-05-04 (lead).</strong> Drop EB Garamond + Inter Tight <code>&lt;link&gt;</code> preconnects from <code>packages/web/index.html</code> in the landing implementation commit, or in a separate cleanup commit? <strong>Same commit. Atomic transition, no dead-preconnect window.</strong> Implementation reflected in §6.2 Type Stack last paragraph.</li><li><strong>Q3. RESOLVED 2026-05-04 (founder, marketer-recommended).</strong> Marquee state copy? <strong>3-state form: <code>recruiting</code> / <code>ceremony-live</code> / <code>live</code>.</strong> Drop <code>pre-ceremony</code> / <code>phase-b-live</code> / <code>pre-launch</code>. Marketer&#39;s reasoning: <code>pre-launch</code> undersells the ceremony milestone; <code>phase-b-live</code> is internal nomenclature; 3 states are user-legible without project-internal context. Implementation reflected in §3.1 (state mapping + 4-state-form-dropped paragraph). Empty-state HN-screenshot guard locked at <code>round — of —</code> when both <code>{N}</code> and <code>{TOTAL}</code> are 0 (also §3.1).</li><li><strong>Q4. DEFERRED.</strong> Component-extraction trigger: at what surface count do the inline-JSX-with-className primitives get extracted to <code>components/civic-terminal/</code>? Spec proposes &quot;after all three surfaces ship + a fourth surface (e.g., extension UI, marketing collateral) emerges.&quot; <strong>Revisit post-rebrand.</strong></li><li><strong>Q5. LOCKED.</strong> Per <code>packages/web/CLAUDE.md</code> invariant #2, all user-visible strings live in <code>i18n/en.json</code> + <code>i18n/uk.json</code>. Variant D&#39;s marquee, legend labels, button labels, ASCII pipeline captions all become i18n keys. Every user-visible string in the new component goes through i18n in the same commit; no English-only landing. Per-worker plan locks the key namespace (proposal: <code>landing.civicTerminal.*</code>).</li><li><strong>Q6. RESOLVED 2026-05-04 (founder, marketer-recommended).</strong> Footer ribbon copy? <strong><code>{BUILD_SHA_7} · {BUILD_DATE} · zkqes.org</code></strong> (7-char truncated SHA + ISO date), via build-time <code>VITE_BUILD_SHA</code> + <code>VITE_BUILD_DATE</code> env. Drop the wireframe&#39;s <code>FORM REVISION 04 · MAY 2026 · SUPERSEDES ALL PRIOR EDITIONS · PAGE 1 OF 1</code> framing. Marketer&#39;s reasoning: SHA reads as credibility move for a ZK project; <code>Form Revision</code> reads as affectation post-reveal. Implementation reflected in §3.5 Footer Ribbon (new subsection).</li></ul><h3 id="_10b-marketer-review-findings-yellow-verdict-7-copy-findings-all-addressed-in-this-amendment-commit" tabindex="-1">10b. Marketer review findings (YELLOW verdict, 7 copy findings, all addressed in this amendment commit) <a class="header-anchor" href="#_10b-marketer-review-findings-yellow-verdict-7-copy-findings-all-addressed-in-this-amendment-commit" aria-label="Permalink to &quot;10b. Marketer review findings (YELLOW verdict, 7 copy findings, all addressed in this amendment commit)&quot;">​</a></h3><ol><li><strong>§3.1 marquee phase tags</strong> — addressed via Q3 lock (3-state collapse).</li><li><strong>§3.2 disabled-tab tooltip</strong> — addressed (<code>Available after trusted setup ceremony + Sepolia testnet deploy</code>; drops internal <code>§9.4</code> reference that&#39;s noise to a cold visitor).</li><li><strong>§3.2 BINDING STATEMENT preview tense</strong> — addressed (active voice: &quot;Holders sign a binding statement that names a wallet, and prove the signature in zk — without disclosing it.&quot;).</li><li><strong>§3.2 empty-state copy</strong> — KEEP VERBATIM (<code>awaiting first contributor (10 needed · 32 GB RAM each)</code>); marketer flagged as screenshot-positive, RAM specificity reads as real infrastructure to a technical audience.</li><li><strong>§3.3 secondary CTA</strong> — addressed (<code>Read the docs ▸</code> → <code>Read the spec ▸</code>; ZK-research audience wants pointer to engineering depth).</li><li><strong>§6.1 BRAND.md Visual Language</strong> — addressed (&quot;AND engineering-credible: the system is built on Groth16/Circom against real eIDAS trust-service infrastructure&quot;; substrate-specific replacement for the prior informal &quot;people who understand the substrate&quot; line).</li><li><strong>§6.3 BRAND.md Component Grammar</strong> — addressed (drop &quot;Claude Design bundle&quot; tool-name reference; replace with stable namespace + amendment-required language).</li></ol><h3 id="_10c-hn-screenshot-mitigation-marketer-2026-05-04" tabindex="-1">10c. HN-screenshot mitigation (marketer 2026-05-04) <a class="header-anchor" href="#_10c-hn-screenshot-mitigation-marketer-2026-05-04" aria-label="Permalink to &quot;10c. HN-screenshot mitigation (marketer 2026-05-04)&quot;">​</a></h3><p>When marquee <code>{N}</code> and <code>{TOTAL}</code> are both <code>0</code> (cold start, feed unreachable, or feed-published pre-recruitment), render <code>round — of —</code> instead of <code>round 0 of 0</code>. The latter looks like a broken counter on a cold-reader screenshot. Implementation reflected in §3.1 marquee bindings.</p><hr><h2 id="acceptance-gate-when-this-spec-is-locked" tabindex="-1">Acceptance gate (when this spec is &quot;locked&quot;) <a class="header-anchor" href="#acceptance-gate-when-this-spec-is-locked" aria-label="Permalink to &quot;Acceptance gate (when this spec is &quot;locked&quot;)&quot;">​</a></h2><ul><li>[x] Marketer review pass complete — 2026-05-04, YELLOW verdict, 7 findings + Q3/Q6 recommendations, all addressed in this amendment commit (§10b)</li><li>[x] Founder confirms Q3 + Q6 — 2026-05-04, locked per marketer recommendations</li><li>[x] Lead confirms Q1 + Q2 — 2026-05-04, locked (CDN with <code>font-display: swap</code> + <code>crossorigin</code>; same-commit preconnect cleanup)</li><li>[ ] Spec committed to main via <code>chore/civic-terminal-spec</code> merge</li></ul><p>After lock:</p><ul><li>Orchestration plan drafts (<code>2026-05-04-zkqes-civic-terminal-orchestration.md</code>)</li><li>Per-worker plan drafts (<code>2026-05-04-zkqes-civic-terminal-web.md</code>)</li><li>BRAND.md amendment commit drafts (founder review)</li><li>Implementation dispatch waves W1 (BRAND) → W2 (landing) → W3 (docs) → W4 (app spec/plan only, implementation deferred)</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Wireframe bundle: <code>/tmp/zkqes-design/zk-qes-3/</code> (Claude Design handoff, decompressed locally)</li><li>Variant D source: <code>/tmp/zkqes-design/zk-qes-3/project/home-variants.jsx::HomeD_Marquee</code> (lines 173-277)</li><li>Token CSS verbatim: <code>/tmp/zkqes-design/zk-qes-3/project/civic-terminal.css</code> (326 lines)</li><li>Prior prototype: <code>feat/v5_3-zkqes-d-prototype @ c242778</code> (superseded; reference for pre-launch adaptation logic)</li><li>Prior visual baseline (now deprecated): <code>packages/web/src/components/LandingHero.tsx</code> (#60), <code>packages/web/src/index.css</code> civic-monumental tokens</li><li>Status feed consumer: <code>packages/web/src/lib/ceremonyStatus.ts</code></li><li>Founder direction thread: 2026-05-04 user-DMs to web-eng (variant D · full rebrand · replace · amend)</li><li>Lead dispatch: 2026-05-04 — option (3) brainstorm-spec-plan-implementation, sequential BRAND→landing→docs→app</li><li>BRAND.md current state: 74 lines, 7 sections (no Visual Language / Type Stack / Component Grammar yet)</li><li><code>packages/web/CLAUDE.md</code> V5.21 invariant: VITE_TARGET landing/app slicing</li><li><code>packages/web/CLAUDE.md</code> V5.22 invariant: root-domain GH Pages SPA-fallback (relevant: any change to <code>dist/index.html</code> shape from the rebrand needs to keep the workflow&#39;s <code>cp dist/index.html dist/404.html</code> path working)</li></ul>',123)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
